import React, { useEffect, useState } from "react";
import { Field, FormSpy } from "react-final-form";
import Wizard from "../../../../common/Wizard";
import { Error, required, Condition } from "../../../../common/Utilitis";
import { InputField } from "../../../../common/InputText";
import FileField from "../../../../common/FileField";
import TreatmentService from "../../../services/treatments.service";
import AppointmentService from "../../../services/appointment.services";
import AuthService from "../../../services/auth.service";
import { useTranslation } from "react-i18next";
import { useNavigate } from "react-router-dom";
function Treatments() {
  const navigate = useNavigate();
  const [t, i18next] = useTranslation();
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState();
  const [treatmentsData, setTreatmentsData] = useState();
  useEffect(async () => {
    // Anything in here is fired on component mount.
    document.body.classList.add("account-page");
    setLoading(true);
    const treatmentServiceResponse = await TreatmentService.getAllTreatments();
    setMessage(
      !!treatmentServiceResponse?.message && treatmentServiceResponse?.message
    );
    if (treatmentServiceResponse.success) {
      setTreatmentsData(
        treatmentServiceResponse.body?.map((s) => {
          return { ...s, isActive: s.isActive };
        })
      );
    }

    setLoading(false);

    return () => {
      // Anything in here is fired on component unmount.
      document.body.classList.remove("account-page");
    };
  }, []);
  const onSubmit = async (values) => {
    const loggedIn = !!AuthService.getCurrentUser();
    if (loggedIn) {
      console.log(`onSubmit :: ${JSON.stringify(values, 0, 2)}`);
      console.log(`onSubmit ::  values.files?.length: ${values.files?.length}`);

      let requestData = new FormData();

      // requestData.append("files", values.files);
      for (let i = 0; i < values.files?.length; i++) {
        requestData.append("files", values.files[i]);
      }
      const request = {
        userId: AuthService.getCurrentUser().id,
        status: "pending",
        treatmentId: values.treatment,
        // treatment: {
        //   id:values.treatment,
        //   facilities: [values.facility],
        // },
      };
      requestData.append("request", JSON.stringify(request, 0, 2));

      const response = await AppointmentService.createAppointmentWithFiles(
        requestData
      );

      setMessage(!!response.message && response.message);
      if (!!!response.success && !response.success) return;
      console.log(`response?.body?.id : ${response?.body?.id}`);
      navigate("/medical-success", {
        state: { values, appointmentId: response?.body?.id },
      });
    } else {
      navigate("/login", { state: { values, history: "/treatments" } });
    }
  };

  const initialValues = {
    treatment: "",
    country: "",
    city: "",
    facility: "",
    isOnBehalf: "",
    symptoms: "",
    files: [],
    patientFirstName: "",
    patientLastName: "",
  };
  const WizatForm = () => (
    <Wizard initialValues={initialValues} onSubmit={onSubmit}>
      <Wizard.Page
        serviceTitle={"Treatments"}
        validate={(values) => {
          const errors = {};
          if (!values.treatment) {
            errors.treatment = required;
          }
          return errors;
        }}
      >
        <>
          {message && (
            <div
              className="invalid-feedback d-block mb-2"
              style={{
                margin:
                  i18next.language === "en" ? "10px 0 0 15px" : "10px 15px 0 0",
              }}
            >
              {message}
            </div>
          )}
          <div className="form-group">
            <Field name="treatment" showerrorbeside="true">
              {({ input, meta }) => {
                return (
                  <select
                    className="form-control select"
                    {...input}
                    onChange={(e) => {
                      input.onChange(e); //final-form's onChange
                    }}
                  >
                    <option value="">
                      {loading === true ? "loading..." : "Select Treatment"}
                    </option>
                    {treatmentsData?.map((val, index) => (
                      <option key={index} value={val.id}>
                        {val.name}
                      </option>
                    ))}
                  </select>
                );
              }}
            </Field>
            <Error name={"treatment"} showerrorbeside="true" />
          </div>
        </>
      </Wizard.Page>
      <Wizard.Page
        serviceTitle={"Country"}
        validate={(values) => {
          const errors = {};
          if (!values.country) {
            errors.country = required;
          }
          return errors;
        }}
      >
        <>
          <div className="form-group">
            <Field name="country" showerrorbeside="true">
              {({ input, meta }) => {
                return (
                  <select
                    className="form-control select"
                    {...input}
                    onChange={(e) => {
                      input.onChange(e); //final-form's onChange
                    }}
                  >
                    <option value="">
                      {loading === true ? "loading..." : "Select Country"}
                    </option>
                    <FormSpy subscription={{ values: true }}>
                      {({ values }) => {
                        console.log(
                          "selected treatment",
                          treatmentsData.filter((t) => t.id === values.treatment)
                        );
                        const countries = treatmentsData
                          .filter((t) => t.id === values.treatment)[0]
                          ?.facilities?.map((val, index) => ({
                            value: val.city.country.id,
                            label: val.city.country.name,
                          }));
                        console.log("countries", countries);
                        const uniqueArr = [
                          ...new Set(countries.map((data) => data.value)),
                        ].map((id) => ({
                          value: id,
                          label: countries.find((c) => c.value === id).label,
                        }));
                        console.log("uniqueArr", uniqueArr);
                        return uniqueArr.map((val, index) => (
                          <option key={index} value={val.value}>
                            {val.label}
                          </option>
                        ));
                      }}
                    </FormSpy>
                  </select>
                );
              }}
            </Field>
            <Error name={"country"} showerrorbeside="true" />
          </div>
        </>
      </Wizard.Page>
      <Wizard.Page
        serviceTitle={"City"}
        validate={(values) => {
          const errors = {};
          if (!values.city) {
            errors.city = required;
          }
          return errors;
        }}
      >
        <>
          <div className="form-group">
            <Field name="city" showerrorbeside="true">
              {({ input, meta }) => {
                return (
                  <select
                    className="form-control select"
                    {...input}
                    onChange={(e) => {
                      input.onChange(e); //final-form's onChange
                    }}
                  >
                    <option value="">
                      {loading === true ? "loading..." : "Select City"}
                    </option>
                    <FormSpy subscription={{ values: true }}>
                      {({ values }) => {
                        const cities = treatmentsData
                          .filter((t) => t.id === values.treatment)[0]
                          ?.facilities?.map((val) => val.city)
                          ?.filter((c) => c.country.id === values.country);
                        console.log("cities", cities);
                        return cities.map((val, index) => (
                          <option key={index} value={val.id}>
                            {val.name}
                          </option>
                        ));
                      }}
                    </FormSpy>
                  </select>
                );
              }}
            </Field>
            <Error name={"city"} showerrorbeside="true" />
          </div>
        </>
      </Wizard.Page>
      <Wizard.Page
        serviceTitle={"Facility"}
        validate={(values) => {
          const errors = {};
          if (!values.facility) {
            errors.facility = required;
          }
          return errors;
        }}
      >
        <>
          <div className="form-group">
            <Field name="facility" showerrorbeside="true">
              {({ input, meta }) => {
                return (
                  <select
                    className="form-control select"
                    {...input}
                    onChange={(e) => {
                      input.onChange(e); //final-form's onChange
                    }}
                  >
                    <option value="">
                      {loading === true ? "loading..." : "Select facility"}
                    </option>
                    <FormSpy subscription={{ values: true }}>
                      {({ values }) => {
                        const facilities = treatmentsData
                          .filter((t) => t.id === values.treatment)[0]
                          ?.facilities?.filter((f) => f.city.id === values.city);
                        console.log("facilities", facilities);
                        return facilities.map((val, index) => (
                          <option key={index} value={val.id}>
                            {val.name}
                          </option>
                        ));
                      }}
                    </FormSpy>
                  </select>
                );
              }}
            </Field>
            <Error name={"facility"} showerrorbeside="true" />
          </div>
        </>
      </Wizard.Page>
      <Wizard.Page
        serviceTitle={"Patient Details"}
        validate={(values) => {
          const errors = {};
          if (!values.symptoms) {
            errors.symptoms = required;
          }
          if (!values.files) {
            errors.files = required;
          }
          if (!values.isOnBehalf) {
            errors.isOnBehalf = "";
          } else if (values.isOnBehalf === "Yes") {
            if (!values.patientFirstName) errors.patientFirstName = required;
            if (!values.patientLastName) errors.patientLastName = required;
          }
          return errors;
        }}
      >
        {message && (
          <div
            className="invalid-feedback d-block mb-2"
            style={{
              margin:
                i18next.language === "en" ? "10px 0 0 15px" : "10px 15px 0 0",
            }}
          >
            {message}
          </div>
        )}
        <div className="card">
          <div className="card-body">
            <h4 className="card-title">Symptoms</h4>
            <div className="row">
              <div className="col-md-12 col-sm-12">
                <div className="form-group card-label">
                  <Field
                    name="symptoms"
                    className="form-control"
                    type="textarea"
                    rows="4"
                    placeholder="Write here symptoms breif..."
                    component={InputField}
                  />
                </div>
              </div>
            </div>
          </div>
        </div>
        <div className="card">
          <div className="card-body">
            <h4 className="card-title">Attachments</h4>
            <div className="row">
              <div className="col-md-12 col-sm-12">
                <div className="form-group card-label">
                  <FileField name="files" multiple />
                  <Error name={"files"} showerrorbeside="true" />
                </div>
              </div>
            </div>
          </div>
        </div>
        <div className="card">
          <div className="card-body">
            <div className="form-group row">
              <h4 className="col-lg-12 card-title">
                Are you booking for someone else?
              </h4>
              <div className="col-lg-12 mt-2">
                <div className="form-check form-check-inline">
                  <Field
                    name="isOnBehalf"
                    id="no_radio"
                    className="form-check-input form-check-inline"
                    component={InputField}
                    type="radio"
                    value="No"
                  />
                  <label htmlFor="no_radio" className="form-check-label">
                    No
                  </label>
                </div>
                <br />
                <div className="form-check form-check-inline">
                  <Field
                    name="isOnBehalf"
                    id="yes_radio"
                    className="form-check-input form-check-inline"
                    component={InputField}
                    value="Yes"
                    type="radio"
                  />
                  <label htmlFor="yes_radio" className="form-check-label">
                    Yes (Please enter patient's info below)
                  </label>
                </div>
              </div>
            </div>
          </div>
        </div>
        <Condition when={"isOnBehalf"} is="Yes">
          <div className="card">
            <div className="card-body">
              <h4 className="card-title">On behalf of</h4>
              <div className="row">
                <div className="col-md-6 col-sm-12">
                  <div className="form-group card-label">
                    <Field
                      name="patientFirstName"
                      className="form-control"
                      type="text"
                      label="First Name"
                      label_type="form_label"
                      component={InputField}
                    />
                  </div>
                </div>
                <div className="col-md-6 col-sm-12">
                  <div className="form-group card-label">
                    <Field
                      name="patientLastName"
                      className="form-control"
                      type="text"
                      label="Last Name"
                      label_type="form_label"
                      component={InputField}
                    />
                  </div>
                </div>
              </div>
            </div>
          </div>
        </Condition>
      </Wizard.Page>
    </Wizard>
  );

  return <WizatForm />;
}

export default Treatments;
